import React, { useState, useEffect } from 'react';

// API functions
const API_BASE_URL = 'http://localhost:5000/api';

const registerUser = async (userData) => {
  try {
    const response = await fetch(`${API_BASE_URL}/auth/register`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(userData)
    });

    const data = await response.json();
    
    if (!response.ok) {
      throw new Error(data.message || 'Registration failed');
    }
    
    return data;
  } catch (error) {
    console.error('Registration error:', error);
    throw error;
  }
};

const RegisterPage = ({ onRegisterSuccess }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    confirmPassword: '',
    role: 'student' // Default role
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);
  const [formVisible, setFormVisible] = useState(false);

  useEffect(() => {
    // Animate form in after component mounts
    setTimeout(() => setFormVisible(true), 100);
    
    // Create animated background elements
    const createAnimatedShapes = () => {
      const container = document.querySelector('.register-background');
      if (!container) return;
      
      // Clear existing shapes
      const existingShapes = container.querySelectorAll('.animated-shape');
      existingShapes.forEach(shape => shape.remove());
      
      // Create shapes for background
      const shapeCount = window.innerWidth > 768 ? 12 : 6;
      
      for (let i = 0; i < shapeCount; i++) {
        const shape = document.createElement('div');
        shape.className = 'animated-shape';
        
        const size = Math.random() * 180 + 40;
        const posX = Math.random() * 100;
        const posY = Math.random() * 100;
        const posZ = Math.random() * 200 - 100;
        const duration = Math.random() * 25 + 15;
        const delay = Math.random() * 8;
        const opacity = Math.random() * 0.5 + 0.1;
        const rotation = Math.random() * 360;
        
        shape.style.width = `${size}px`;
        shape.style.height = `${size}px`;
        shape.style.left = `${posX}%`;
        shape.style.top = `${posY}%`;
        shape.style.transform = `translateZ(${posZ}px) rotate(${rotation}deg)`;
        shape.style.animationDuration = `${duration}s`;
        shape.style.animationDelay = `${delay}s`;
        shape.style.opacity = opacity;
        
        // Add random shape types
        const shapeType = Math.floor(Math.random() * 5);
        
        if (shapeType === 0) {
          shape.style.borderRadius = '50%';
        } else if (shapeType === 1) {
          shape.style.borderRadius = '30%';
        } else if (shapeType === 2) {
          shape.style.clipPath = 'polygon(50% 0%, 100% 38%, 82% 100%, 18% 100%, 0% 38%)';
        } else if (shapeType === 3) {
          shape.style.clipPath = 'polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%)';
        } else {
          shape.style.clipPath = 'polygon(50% 0%, 100% 100%, 0% 100%)';
        }
        
        if (Math.random() > 0.7) {
          shape.style.boxShadow = '0 0 20px 5px rgba(0, 123, 255, 0.2)';
        }
        
        container.appendChild(shape);
      }
    };
    
    createAnimatedShapes();
    window.addEventListener('resize', createAnimatedShapes);
    
    return () => {
      window.removeEventListener('resize', createAnimatedShapes);
    };
  }, []);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const nextStep = () => {
    if (currentStep === 1) {
      if (!formData.firstName || !formData.lastName) {
        setError('Please fill in all fields to continue.');
        return;
      }
    } else if (currentStep === 2) {
      if (!formData.email || !formData.role) {
        setError('Please fill in all fields to continue.');
        return;
      }
    }
    setError('');
    setCurrentStep(currentStep + 1);
  };

  const prevStep = () => {
    setError('');
    setCurrentStep(currentStep - 1);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    
    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters long');
      return;
    }
    
    setLoading(true);
    setError('');
    
    try {
      // Prepare data for backend
      const registrationData = {
        email: formData.email,
        password: formData.password,
        role: formData.role
      };
      
      const response = await registerUser(registrationData);
      
      setSuccess(true);
      
      // Show success message based on role
      if (formData.role === 'student') {
        setTimeout(() => {
          if (onRegisterSuccess) {
            onRegisterSuccess();
          }
          window.location.href = '/';
        }, 3000);
      }
      
    } catch (error) {
      setError(error.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const renderStep = () => {
    switch(currentStep) {
      case 1:
        return (
          <>
            <h3 style={styles.stepTitle}>Personal Details</h3>
            <div style={styles.formGroup}>
              <input
                type="text"
                id="firstName"
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                required
                style={styles.input}
                placeholder="First Name"
              />
              <span style={styles.inputIcon} className="material-icons">person</span>
            </div>
            
            <div style={styles.formGroup}>
              <input
                type="text"
                id="lastName"
                name="lastName"
                value={formData.lastName}
                onChange={handleChange}
                required
                style={styles.input}
                placeholder="Last Name"
              />
              <span style={styles.inputIcon} className="material-icons">person</span>
            </div>
          </>
        );
      case 2:
        return (
          <>
            <h3 style={styles.stepTitle}>Account Details</h3>
            <div style={styles.formGroup}>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                style={styles.input}
                placeholder="Email Address"
              />
              <span style={styles.inputIcon} className="material-icons">email</span>
            </div>
            
            <div style={styles.formGroup}>
              <select
                name="role"
                value={formData.role}
                onChange={handleChange}
                style={styles.select}
                required
              >
                <option value="student">Student</option>
                <option value="teacher">Teacher</option>
              </select>
              <span style={styles.inputIcon} className="material-icons">school</span>
            </div>
            
            {formData.role !== 'student' && (
              <div style={styles.infoBox}>
                <span className="material-icons" style={styles.infoIcon}>info</span>
                <p>Teacher accounts require admin approval before you can log in.</p>
              </div>
            )}
          </>
        );
      case 3:
        return (
          <>
            <h3 style={styles.stepTitle}>Secure Your Account</h3>
            <div style={styles.formGroup}>
              <input
                type="password"
                id="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                required
                style={styles.input}
                placeholder="Password (min 6 characters)"
              />
              <span style={styles.inputIcon} className="material-icons">lock</span>
            </div>
            
            <div style={styles.formGroup}>
              <input
                type="password"
                id="confirmPassword"
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleChange}
                required
                style={styles.input}
                placeholder="Confirm Password"
              />
              <span style={styles.inputIcon} className="material-icons">lock</span>
            </div>
          </>
        );
      default:
        return null;
    }
  };

  return (
    <div style={styles.registerPage}>
      <div className="register-background" style={styles.registerBackground}>
        {/* Animated shapes will be added by useEffect */}
      </div>
      
      <div style={{...styles.registerContainer, ...(formVisible ? styles.containerVisible : {})}}>
        <div style={styles.glassEffect}></div>
        
        <div style={styles.registerContent}>
          <h2 style={styles.registerTitle}>Join Our Community</h2>
          
          {!success ? (
            <>
              <div style={styles.stepper}>
                {[1, 2, 3].map((step) => (
                  <React.Fragment key={step}>
                    <div style={{
                      ...styles.step,
                      ...(currentStep >= step ? styles.stepActive : {}),
                      ...(currentStep > step ? styles.stepCompleted : {})
                    }}>
                      <div style={styles.stepNumber}>
                        {currentStep > step ? '✓' : step}
                      </div>
                      <div style={styles.stepLabel}>
                        {step === 1 ? 'Personal' : step === 2 ? 'Account' : 'Security'}
                      </div>
                    </div>
                    {step < 3 && <div style={styles.stepLine}></div>}
                  </React.Fragment>
                ))}
              </div>
              
              {error && (
                <div style={styles.errorMessage}>
                  <span className="material-icons">error</span>
                  <span>{error}</span>
                </div>
              )}
              
              <form onSubmit={currentStep === 3 ? handleSubmit : (e) => e.preventDefault()}>
                <div style={styles.formStepsContainer}>
                  {renderStep()}
                </div>
                
                <div style={styles.formNavigation}>
                  {currentStep > 1 && (
                    <button 
                      type="button"
                      style={styles.btnPrev}
                      onClick={prevStep}
                    >
                      <span className="material-icons">arrow_back</span>
                      Back
                    </button>
                  )}
                  
                  {currentStep < 3 ? (
                    <button 
                      type="button"
                      style={styles.btnNext}
                      onClick={nextStep}
                    >
                      Next
                      <span className="material-icons">arrow_forward</span>
                    </button>
                  ) : (
                    <button 
                      type="submit"
                      style={{...styles.btnSubmit, ...(loading ? styles.btnLoading : {})}}
                      disabled={loading}
                    >
                      {loading ? (
                        <>
                          <span style={styles.spinner}></span>
                          Registering...
                        </>
                      ) : (
                        <>
                          Register
                          <span className="material-icons">check</span>
                        </>
                      )}
                    </button>
                  )}
                </div>
              </form>
            </>
          ) : (
            <div style={styles.successMessage}>
              <div style={styles.successIcon}>
                <span className="material-icons">check_circle</span>
              </div>
              <h3>Registration Successful!</h3>
              {formData.role === 'student' ? (
                <>
                  <p>Your account has been created. Redirecting to login...</p>
                  <div style={styles.loader}></div>
                </>
              ) : (
                <p>Your account has been created and is pending admin approval. You'll be notified once approved.</p>
              )}
            </div>
          )}
          
          <div style={styles.loginLink}>
            Already have an account?{' '}
            <a href="#" onClick={(e) => {
              e.preventDefault();
              window.location.href = '/';
              if (onRegisterSuccess) onRegisterSuccess();
            }}>
              Log in
            </a>
          </div>
        </div>
      </div>
    </div>
  );
};

